def parse_monto(s):
    try:
        return int(s)
    except ValueError as e:
        raise ValueError(f'monto invalido: {s!r}') from e
try:
    parse_monto('x')
except ValueError as e:
    print(type(e).__name__, e)
    print('cause', e.__cause__)

