def parse_dni(d: str) -> str:
    if not (d.isdigit() and len(d) == 8):
        raise ValueError(f'dni invalido: {d!r}')
    return d
fixture = ['12345678', '123', '87654321', '12AB5678']
minimal = None
for d in fixture:
    try:
        parse_dni(d)
    except ValueError:
        minimal = d
        break
print('minimal=', minimal)

def normalize_phone(p: str) -> str:
    return ''.join(c for c in p if c.isdigit())
print('H1: se pierde + pero debe quedar 51')
print('H2: si no habia 51, no inventarlo')
print('exp1', normalize_phone('+51 999 111 222'))
print('exp2', normalize_phone('999 111 222'))

def bad_title(s: str) -> str:
    return s.title()
def good_title(s: str) -> str:
    parts = s.split()
    out = []
    for i, p in enumerate(parts):
        if i > 0 and p.lower() in {'de', 'del', 'la', 'los', 'las', 'y'}:
            out.append(p.lower())
        else:
            out.append(p[:1].upper() + p[1:].lower() if p else p)
    return ' '.join(out)
def test(fn):
    out = fn('juan de la cruz')
    assert out == 'Juan de la Cruz', out
    return 'pass'
try:
    test(bad_title)
except AssertionError:
    print('RED')
print(test(good_title))
print('GREEN')

def mask_email(email: str) -> str:
    local, _, domain = email.partition('@')
    if not domain:
        return '***'
    return (local[:1] + '***@' + domain) if local else '***@' + domain
def mask_phone(phone: str) -> str:
    digits = ''.join(c for c in phone if c.isdigit())
    return '***' + digits[-4:] if len(digits) >= 4 else '***'
print(mask_email('carlos@ejemplo.pe'))
print(mask_phone('+51 988 777 666'))

